const body = $input.first().json.body || $input.first().json;
const errors = [];

if (!body.client_id) errors.push('client_id missing');
if (!body.keyword) errors.push('keyword missing');
if (!body.email || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(body.email)) errors.push('invalid email');
if (!body.consent || body.consent !== true) errors.push('consent must be true');

if (errors.length > 0) throw new Error('Validation: ' + errors.join('; '));

return [{ json: {
  client_id: body.client_id,
  chatfuel_user_id: body.chatfuel_user_id || null,
  tiktok_user_id: body.tiktok_user_id || null,
  keyword: (body.keyword || '').toUpperCase().trim(),
  email: (body.email || '').toLowerCase().trim(),
  consent: true,
  free_resource_url: body.free_resource_url || null,
  payload: body
} }];

// Log to Supabase events table (separate HTTP node in production)
// Return Chatfuel retry message in expected format
return [{ json: { messages: [{ text: 'Something went wrong. Please try again in a moment.' }] } }];
